import React, { useState } from 'react';
import AdminSidebar from './AdminSidebar.jsx';
import StatCard from './StatCard.jsx';
import BookingsTable from './BookingsTable.jsx';
import AdminCalendarView from './AdminCalendarView.jsx';
import { MOCK_BOOKINGS } from '../../data/mockBookings.js';
import { BOOKED_DATES } from '../../data/bookingStore.js';
import styles from '../../styles/admin/AdminDashboard.module.css';

const AdminDashboard = ({ admin, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [bookings, setBookings] = useState(MOCK_BOOKINGS);
  const [blockedDates, setBlockedDates] = useState(new Set(BOOKED_DATES));

  const togglePaid = (id) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, paid: !b.paid } : b));
  };

  const cancelBooking = (id) => {
    if (window.confirm('Cancel this booking?')) {
      setBookings(prev => prev.map(b => b.id === id ? { ...b, status: 'cancelled' } : b));
    }
  };

  const toggleBlock = (dateStr) => {
    setBlockedDates(prev => {
      const next = new Set(prev);
      if (next.has(dateStr)) next.delete(dateStr);
      else next.add(dateStr);
      return next;
    });
  };

  // Stats
  const active = bookings.filter(b => b.status !== 'cancelled');
  const totalRevenue = active.reduce((s, b) => s + b.total, 0);
  const paidCount = active.filter(b => b.paid).length;
  const unpaidCount = active.filter(b => !b.paid).length;
  const paidRevenue = active.filter(b => b.paid).reduce((s, b) => s + b.total, 0);

  const upcomingBookings = active
    .filter(b => b.checkIn >= new Date().toISOString().slice(0, 10))
    .sort((a, b) => a.checkIn.localeCompare(b.checkIn))
    .slice(0, 5);

  return (
    <div className={styles.layout}>
      <AdminSidebar
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        adminEmail={admin.email}
        onLogout={onLogout}
      />

      <main className={styles.main}>
        <div className={styles.topBar}>
          <div>
            <h1 className={styles.pageTitle}>
              {activeTab === 'dashboard' && 'Dashboard'}
              {activeTab === 'bookings'  && 'All Bookings'}
              {activeTab === 'calendar'  && 'Booking Calendar'}
              {activeTab === 'blocked'   && 'Blocked Dates'}
            </h1>
            <p className={styles.pageDate}>
              {new Date().toLocaleDateString('en-PH', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
          </div>
          <a href="/" className={styles.viewSiteBtn} target="_blank" rel="noreferrer">
            View Guest Site →
          </a>
        </div>

        {/* ── DASHBOARD TAB ── */}
        {activeTab === 'dashboard' && (
          <div className={styles.content}>
            <div className={styles.statsGrid}>
              <StatCard icon="📋" label="Total Bookings"  value={active.length}              sub={`${bookings.filter(b=>b.status==='cancelled').length} cancelled`} accent="crimson" />
              <StatCard icon="💰" label="Total Revenue"   value={`₱${totalRevenue.toLocaleString()}`} sub="all active bookings"   accent="gold" />
              <StatCard icon="✓"  label="Paid"            value={paidCount}                  sub={`₱${paidRevenue.toLocaleString()} collected`}  accent="teal" />
              <StatCard icon="⏳" label="Awaiting Payment" value={unpaidCount}               sub="need follow-up" />
            </div>

            <div className={styles.section}>
              <div className={styles.sectionHeader}>
                <h2 className={styles.sectionTitle}>Upcoming Arrivals</h2>
                <button className={styles.seeAllBtn} onClick={() => setActiveTab('bookings')} type="button">
                  See all →
                </button>
              </div>
              <div className={styles.upcomingList}>
                {upcomingBookings.length === 0 && (
                  <p className={styles.emptyNote}>No upcoming arrivals.</p>
                )}
                {upcomingBookings.map(b => (
                  <div key={b.id} className={styles.upcomingCard}>
                    <div className={styles.upcomingRoom}>{b.room.icon}</div>
                    <div className={styles.upcomingInfo}>
                      <div className={styles.upcomingName}>{b.guestName}</div>
                      <div className={styles.upcomingMeta}>{b.room.name} · {b.nights} nights · {b.guests} pax</div>
                    </div>
                    <div className={styles.upcomingDate}>
                      <div className={styles.upcomingDateVal}>{new Date(b.checkIn + 'T00:00:00').toLocaleDateString('en-PH', { month: 'short', day: 'numeric' })}</div>
                      <div className={styles.upcomingDateSub}>Check-in</div>
                    </div>
                    <div>
                      <span className={`${styles.paidPill} ${b.paid ? styles.paidPillYes : styles.paidPillNo}`}>
                        {b.paid ? 'Paid' : 'Unpaid'}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className={styles.twoCol}>
              <div className={styles.section}>
                <h2 className={styles.sectionTitle}>Revenue Breakdown</h2>
                <div className={styles.revenueBar}>
                  <div
                    className={styles.revenueBarFill}
                    style={{ width: totalRevenue > 0 ? `${(paidRevenue / totalRevenue) * 100}%` : '0%' }}
                  />
                </div>
                <div className={styles.revenueLegend}>
                  <span className={styles.revenuePaid}>₱{paidRevenue.toLocaleString()} paid</span>
                  <span className={styles.revenueUnpaid}>₱{(totalRevenue - paidRevenue).toLocaleString()} pending</span>
                </div>
              </div>

              <div className={styles.section}>
                <h2 className={styles.sectionTitle}>Quick Actions</h2>
                <div className={styles.quickActions}>
                  <button className={styles.qaBtn} onClick={() => setActiveTab('bookings')} type="button">📋 View All Bookings</button>
                  <button className={styles.qaBtn} onClick={() => setActiveTab('blocked')} type="button">🚫 Manage Blocked Dates</button>
                  <button className={styles.qaBtn} onClick={() => setActiveTab('calendar')} type="button">📅 View Calendar</button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── BOOKINGS TAB ── */}
        {activeTab === 'bookings' && (
          <div className={styles.content}>
            <BookingsTable
              bookings={bookings}
              onTogglePaid={togglePaid}
              onCancelBooking={cancelBooking}
            />
          </div>
        )}

        {/* ── CALENDAR TAB ── */}
        {activeTab === 'calendar' && (
          <div className={styles.content}>
            <p className={styles.calNote}>
              🌸 This calendar shows all guest bookings. Switch to <strong>Blocked Dates</strong> to manually block availability.
            </p>
            <AdminCalendarView
              bookings={bookings}
              blockedDates={blockedDates}
              onToggleBlock={toggleBlock}
            />
          </div>
        )}

        {/* ── BLOCKED DATES TAB ── */}
        {activeTab === 'blocked' && (
          <div className={styles.content}>
            <p className={styles.calNote}>
              🚫 Click any available date to block it. Click a blocked date to unblock. Guest-booked dates cannot be changed here.
            </p>
            <AdminCalendarView
              bookings={bookings}
              blockedDates={blockedDates}
              onToggleBlock={toggleBlock}
            />
            <div className={styles.blockedList}>
              <h3 className={styles.blockedTitle}>Currently Blocked ({blockedDates.size} dates)</h3>
              <div className={styles.blockedTags}>
                {[...blockedDates].sort().map(d => (
                  <span key={d} className={styles.blockedTag}>
                    {d}
                    <button className={styles.removeTag} onClick={() => toggleBlock(d)} type="button">×</button>
                  </span>
                ))}
                {blockedDates.size === 0 && <p className={styles.emptyNote}>No dates blocked.</p>}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;
